const statsRaw = $('Fetch Geo Stats (7 days)').first().json;
const crmItems = $('Fetch CRM Leads by Geo').all().map(i => i.json);

const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

if (!Array.isArray(stats) || stats.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No geo stats data' } }];
}

// Build CRM map: ad_id+geo -> {leads, depositors, revenue}
const crmMap = {};
crmItems.forEach(row => {
  const key = `${row.ad_id}_${(row.geo || '').toUpperCase()}`;
  crmMap[key] = {
    leads: Number(row.total_leads) || 0,
    depositors: Number(row.depositors) || 0,
    revenue: Number(row.crm_revenue) || 0
  };
});

const results = [];
stats.forEach(d => {
  const adId = d.ad_id;
  const country = d.country_code;
  if (!adId || !country) return;

  const spend = Number(d.money) || 0;
  const key = `${adId}_${country.toUpperCase()}`;
  const crm = crmMap[key] || { leads: 0, depositors: 0, revenue: 0 };
  const roi = spend > 0 ? Math.round((crm.revenue - spend) / spend * 10000) / 100 : 0;
  const cpl = crm.leads > 0 ? Math.round(spend / crm.leads * 100) / 100 : 0;

  results.push({
    json: {
      ad_id: adId,
      country_code: country,
      shows: Number(d.shows_count) || 0,
      clicks: Number(d.clicks_count) || 0,
      spend: Math.round(spend * 100) / 100,
      revenue: Math.round(crm.revenue * 100) / 100,
      leads: crm.leads,
      depositors: crm.depositors,
      cpl: cpl,
      roi: roi
    }
  });
});

return results;
